  1→import React, { useState, useMemo, useCallback, useEffect } from 'react';
  2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
  3→import { analyzeUrl } from './services/analyzer';
  4→import { db } from './services/database';
  5→import Home from './pages/Home';
  6→import Login from './pages/Login';
  7→import Dashboard from './pages/Dashboard';
  8→import GenerativeTools from './pages/GenerativeTools';
  9→import Analyze from './pages/Analyze';
 10→import { Results } from './pages/Results';
 11→import HistoryView from './pages/History';
 12→import SMCStudio from './pages/SMCStudio';
 13→import SourceOfTruth from './pages/SourceOfTruth';
 14→import SchemaOrg from './pages/SchemaOrg';
 15→import PublisherRequest from './pages/PublisherRequest';
 16→import RobotsTxt from './pages/RobotsTxt';
 17→import Directory from './pages/Directory';
 18→import DirectoryEntity from './pages/DirectoryEntity';
 19→import Recharge from './pages/Recharge';
 20→import Plan from './pages/Plan';
 21→import Projects from './pages/Projects';
 22→import Account from './pages/Account';
 23→import Clients from './pages/Clients';
 24→import Affiliation from './pages/Affiliation';
 25→import ContentWriter from './pages/ContentWriter';
 26→import Reputation from './pages/Reputation';
 27→import {
 28→  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
 29→  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
 30→  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
 31→  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
 32→  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield
 33→} from 'lucide-react';
 34→import { I18nProvider, useTranslation, LanguageSelector } from './i18n';
 35→
 36→const PLAN_LIMITS = {
 37→  free: 1,
 38→  pro: 3,
 39→  enterprise: 1000 // Illimité en pratique
 40→};
 41→
 42→const App: React.FC = () => {
 43→  return (
 44→    <I18nProvider>
 45→      <AppContent />
 46→    </I18nProvider>
 47→  );
 48→};
 49→
 50→const AppContent: React.FC = () => {
 51→  const { t, tf, locale } = useTranslation();
 52→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'plan' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation'>('home');
 53→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 54→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 55→  
 56→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 57→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 58→  
 59→  // Load history from DB on mount
 60→  useEffect(() => {
 61→    const loadedHistory = db.getAll();
 62→    setHistory(loadedHistory);
 63→  }, []);
 64→
 65→  // Bibliothèques de contenu généré
 66→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 67→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 68→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 69→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 70→
 71→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 72→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
 73→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
 74→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
 75→  const [initialPlanTab, setInitialPlanTab] = useState<'my-plan' | 'pricing' | 'billing'>('my-plan');
 76→  
 77→  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
 78→  const [sectionsState, setSectionsState] = useState({
 79→    optimization: false,
 80→    tools: false
 81→  });
 82→
 83→  // Default user is NULL to allow testing the login flow
 84→  const [user, setUser] = useState<User | null>(null);
 85→
 86→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 87→  const monthlyProjectCount = useMemo(() => {
 88→    if (history.length === 0) return 0;
 89→
 90→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 91→    const now = new Date();
 92→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 93→
 94→    // 1. Identifier la date de création (première analyse) de chaque domaine
 95→    const projectCreationDates = new Map<string, Date>();
 96→    
 97→    history.forEach(h => {
 98→        let hostname;
 99→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
100→        
101→        const analysisDate = new Date(h.timestamp);
102→        
103→        if (!projectCreationDates.has(hostname)) {
104→            projectCreationDates.set(hostname, analysisDate);
105→        } else {
106→            // On garde la date la plus ancienne trouvée pour ce domaine
107→            if (analysisDate < projectCreationDates.get(hostname)!) {
108→                projectCreationDates.set(hostname, analysisDate);
109→            }
110→        }
111→    });
112→
113→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
114→    let count = 0;
115→    projectCreationDates.forEach((creationDate) => {
116→        if (creationDate >= billingCycleStart) {
117→            count++;
118→        }
119→    });
120→    
121→    return count;
122→  }, [history]);
123→
124→  const navigateTo = (view: typeof currentView) => {
125→    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
126→    if (view !== 'recharge') {
127→        setInitialRechargePackId(null);
128→    }
129→    // Reset l'onglet du plan si on ne va pas vers le plan
130→    if (view !== 'plan') {
131→        setInitialPlanTab('my-plan');
132→    }
133→    setViewHistory(prev => [...prev, currentView]);
134→    setCurrentView(view);
135→    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
136→  };
137→
138→  const goBack = () => {
139→    if (viewHistory.length > 0) {
140→      const newHistory = [...viewHistory];
141→      const prevView = newHistory.pop();
142→      setViewHistory(newHistory);
143→      if (prevView) {
144→        setCurrentView(prevView as any);
145→        setRefreshKey(prev => prev + 1);
146→      }
147→    } else {
148→      setCurrentView('home'); // Default fallback
149→      setRefreshKey(prev => prev + 1);
150→    }
151→  };
152→
153→  const toggleSection = (section: keyof typeof sectionsState) => {
154→    setSectionsState(prev => {
155→      const isAlreadyOpen = prev[section];
156→      return {
157→        optimization: false,
158→        tools: false,
159→        [section]: !isAlreadyOpen
160→      };
161→    });
162→  };
163→
164→  const handleHomeClick = () => {
165→    navigateTo('home');
166→    setSectionsState({
167→      optimization: false,
168→      tools: false
169→    });
170→  };
171→
172→  const handleDashboardClick = () => {
173→    navigateTo('dashboard');
174→    setSectionsState({
175→      optimization: false,
176→      tools: false
177→    });
178→  };
179→
180→  const handleRechargeClick = () => {
181→    navigateTo('recharge');
182→    setSectionsState({
183→      optimization: false,
184→      tools: false
185→    });
186→  };
187→
188→  const handleDirectRecharge = (packId: number) => {
189→    setInitialRechargePackId(packId);
190→    navigateTo('recharge');
191→  };
192→
193→  const handleAnalyze = async (url: string) => {
194→    // Vérification de la limite de projets (Quota mensuel)
195→    if (user) {
196→        const limit = PLAN_LIMITS[user.plan] || 1;
197→        let hostname = url;
198→        try { hostname = new URL(url).hostname; } catch(e) {}
199→
200→        // On vérifie si c'est un projet déjà existant dans l'historique global
201→        const isExistingProject = history.some(h => {
202→            try { return new URL(h.url).hostname === hostname; } 
203→            catch(e) { return false; }
204→        });
205→
206→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
207→        // Les anciens projets ne comptent pas dans cette limite
208→        if (!isExistingProject && monthlyProjectCount >= limit) {
209→            // Redirection directe vers la page Plan
210→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
211→            navigateTo('plan');
212→            return;
213→        }
214→    }
215→
216→    setIsAnalyzing(true);
217→    try {
218→      const result = await analyzeUrl(url);
219→      setAnalysisData(result);
220→      
221→      // Update history via DB service
222→      const updatedHistory = db.add(result);
223→      setHistory(updatedHistory);
224→      
225→      // Redirection vers Monitoring AEO (Projects)
226→      navigateTo('projects');
227→      setSectionsState({
228→        optimization: false,
229→        tools: false
230→      });
231→    } catch (error) {
232→      console.error("Analysis failed", error);
233→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
234→    } finally {
235→      setIsAnalyzing(false);
236→    }
237→  };
238→
239→  // Used for Admin/User private analysis view
240→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
241→    setAnalysisData(result);
242→    setResultsTab(tab);
243→    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
244→    navigateTo('projects');
245→    setSectionsState({
246→        optimization: true,
247→        tools: false
248→    });
249→  };
250→
251→  // New handler for Public Directory View
252→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
253→    setAnalysisData(result);
254→    navigateTo('directory-entity');
255→  };
256→
257→  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
258→    if (analysisData) {
259→      setResultsTab(tab);
260→      navigateTo('results');
261→    } else if (history.length > 0) {
262→      handleViewAnalysis(history[0], tab);
263→    } else {
264→      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
265→      navigateTo('analyze');
266→    }
267→  };
268→
269→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
270→    const updatedHistory = db.update(index, updatedData);
271→    setHistory(updatedHistory);
272→  };
273→
274→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
275→    const timestamp = new Date().toISOString();
276→    const solutionWithMeta = { ...solution, timestamp };
277→
278→    setAnalysisData(prev => {
279→        if (!prev || prev.timestamp !== analysisId) return prev;
280→        
281→        return {
282→            ...prev,
283→            generatedSolutions: {
284→                ...(prev.generatedSolutions || {}),
285→                [recommendationId]: solutionWithMeta
286→            }
287→        };
288→    });
289→
290→    // We need to find the index in the history to update the DB
291→    setHistory(prevHistory => {
292→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
293→        if (index !== -1) {
294→            const updatedItem = {
295→                ...prevHistory[index],
296→                generatedSolutions: {
297→                    ...(prevHistory[index].generatedSolutions || {}),
298→                    [recommendationId]: solutionWithMeta
299→                }
300→            };
301→            // Persist using db service
302→            const newHistory = [...prevHistory];
303→            newHistory[index] = updatedItem;
304→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
305→            db.update(index, updatedItem);
306→            return newHistory;
307→        }
308→        return prevHistory;
309→    });
310→  }, []); 
311→
312→  // Helpers pour ajouter du contenu aux bibliothèques
313→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
314→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
315→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
316→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
317→
318→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
319→    setPublisherRequestData(data);
320→    navigateTo('publisher-request');
321→  };
322→
323→  const handleNavigateToDirectory = () => {
324→    navigateTo('directory');
325→  };
326→
327→  const handleDeductCredits = (amount: number): boolean => {
328→    if (!user) {
329→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
330→            navigateTo('login');
331→        }
332→        return false;
333→    }
334→    
335→    if (user.credits < amount) {
336→        // Redirection explicite vers la section GTO Gas (Recharge)
337→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
338→        navigateTo('recharge');
339→        return false;
340→    }
341→    
342→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
343→    return true;
344→  };
345→
346→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
347→    if (!user) return;
348→    
349→    setUser({ 
350→        ...user, 
351→        credits: user.credits + amount,
