              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.brandUrl} ({t.common.optional})</label>
                <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
              </div>
            </div>
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.productOrService} *</label>
              <input value={productOrService} onChange={e => setProductOrService(e.target.value)} placeholder="Ex: AEO optimization platform" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.targetAudience} *</label>
              <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="Ex: B2B Marketing Directors" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
