                  <option value="es">{t.contentWriter.contentLanguages.es}</option>
                </select>
              </div>
              <div className="flex items-end">
                <div className="bg-rose-500/10 border border-rose-500/20 rounded-lg px-4 py-3 text-center w-full">
                  <span className="text-xs text-gray-400">{t.common.score}</span>
