              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 bg-white/5 rounded-lg hover:bg-white/10 transition-colors" title={t.common.download}>
                <Download size={16} className="text-gray-400" />
              </button>
              <button onClick={handleRegenerate} className="p-2.5 bg-white/5 rounded-lg hover:bg-white/10 transition-colors" title={t.common.regenerate}>
                <RefreshCw size={16} className="text-gray-400" />
              </button>
            </div>
          </div>

          {/* AEO Tips */}
          {result.aeoTips.length > 0 && (
            <div className="mb-6 bg-rose-500/5 border border-rose-500/10 rounded-xl p-5">
              <h4 className="text-sm font-bold text-rose-400 mb-3">{t.contentWriter.aeoTips}</h4>
              <ul className="space-y-1.5">
                {result.aeoTips.map((tip, i) => (
                  <li key={i} className="text-sm text-gray-300 flex items-start gap-2">
                    <span className="text-rose-400 mt-0.5">&#x2022;</span> {tip}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Content */}
          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 leading-relaxed">
              {result.content}
            </div>
          </div>

          {/* Schema Markup */}
          {result.schemaMarkup && (
            <div className="mt-6 bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
              <div className="flex items-center justify-between mb-3">
                <h4 className="text-sm font-bold text-gray-200">{t.contentWriter.schemaJsonLd}</h4>
                <button onClick={() => handleCopy(result.schemaMarkup || '')} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                  <Copy size={12} /> {t.common.copy}
                </button>
              </div>
              <pre className="text-xs text-emerald-400 bg-black/40 rounded-lg p-4 overflow-x-auto">{result.schemaMarkup}</pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ContentWriter;

