354→                        <p className="text-xs text-gray-400 mt-1">Action : {alert.action}</p>
355→                      </div>
356→                      <button
357→                        onClick={() => handleGenerateActionPlan(alert, i)}
358→                        className={`text-xs px-3 py-1.5 rounded-lg border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-white/5`}
359→                      >
360→                        <Sparkles size={12} /> {t.reputation.actionPlan}
361→                      </button>
362→                    </div>
363→                    {isExpanded && (
