import React from 'react';
import { PenTool, FileText, Code, FileCode, Search, Sparkles, AlertTriangle, Feather, Shield } from 'lucide-react';
import { useTranslation } from '../i18n';

interface GenerativeToolsProps {
  onNavigate: (view: any) => void;
}

interface ToolCardProps {
  icon: React.ElementType;
  label: string;
  desc: string;
  color: string;
  bg: string;
  onClick: () => void;
}

const ToolCard: React.FC<ToolCardProps> = ({ icon: Icon, label, desc, color, bg, onClick }) => (
  <button
    onClick={onClick}
    className="bg-[#1a1d21] border border-white/5 rounded-2xl p-8 flex flex-col items-center justify-center gap-6 hover:bg-white/5 transition-all hover:-translate-y-1 group h-full shadow-lg hover:shadow-xl hover:border-white/10"
  >
    <div className={`p-5 rounded-2xl ${bg} group-hover:scale-110 transition-transform duration-300`}>
      <Icon size={48} className={color} />
    </div>
    <div className="text-center space-y-2">
      <span className="block text-xl font-bold text-gray-200 group-hover:text-white transition-colors">{label}</span>
      <span className="block text-sm text-gray-500 group-hover:text-gray-400 transition-colors">{desc}</span>
    </div>
  </button>
);

const GenerativeTools: React.FC<GenerativeToolsProps> = ({ onNavigate }) => {
  const { t } = useTranslation();

  const tools = [
    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-orange-400', bg: 'bg-orange-500/10', desc: t.generativeTools.smcStudioDesc },
    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-rose-400', bg: 'bg-rose-500/10', desc: t.generativeTools.contentWriterDesc },
    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-amber-400', bg: 'bg-amber-500/10', desc: t.generativeTools.reputationDesc },
    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-emerald-400', bg: 'bg-emerald-500/10', desc: t.generativeTools.robotsTxtDesc },
  ];

  return (
    <div className="max-w-[1400px] mx-auto px-6 py-8 animate-in fade-in duration-500">

      {/* Header style Dashboard Pro */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
        <div className="flex items-center gap-4">
          <h1 className="text-3xl font-bold text-white">{t.generativeTools.title}</h1>
          <span className="bg-primary/10 text-primary text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
            <Sparkles size={12} /> {t.generativeTools.suitePro}
          </span>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <input
              type="text"
              placeholder={t.generativeTools.searchPlaceholder}
              className="bg-[#1a1d21] border border-white/10 rounded-lg py-2.5 pl-4 pr-10 text-sm text-gray-300 focus:outline-none focus:border-primary w-full md:w-80 transition-all"
            />
            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" />
          </div>
        </div>
      </div>

      {/* Grid des Outils */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
        {tools.map((tool) => (
            <ToolCard
                key={tool.id}
                icon={tool.icon}
                label={tool.label}
                desc={tool.desc}
                color={tool.color}
                bg={tool.bg}
                onClick={() => onNavigate(tool.id)}
            />
        ))}
      </div>

      {/* Section Explicative */}
      <div className="p-8 bg-[#1a1d21] border border-white/5 rounded-2xl">
        <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-white/5 rounded-lg">
                <AlertTriangle size={20} className="text-yellow-400" />
            </div>
            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
                <p className="text-sm text-gray-400 leading-relaxed">
                    {t.generativeTools.structuredContentDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.technicalData}</h4>
                <p className="text-sm text-gray-400 leading-relaxed">
                    {t.generativeTools.technicalDataDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.sourceAuthority}</h4>
                <p className="text-sm text-gray-400 leading-relaxed">
                    {t.generativeTools.sourceAuthorityDesc}
                </p>
            </div>
        </div>
      </div>

    </div>
  );
};

export default GenerativeTools;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ReputationScanInput, ReputationReport, AIMention } from '../types';

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// ================================================================
// PROMPTS
// ================================================================

export const REPUTATION_SCAN_PROMPT = `
# ROLE
Tu es un Analyste de Reputation Digitale & Expert en Visibilite IA chez CitedBy.ai.

# MISSION
Simule une analyse de reputation d'une marque telle qu'elle apparaitrait dans les reponses des moteurs de reponse IA.

DISCLAIMER IMPORTANT : Cette analyse est une SIMULATION HEURISTIQUE basee sur des patterns connus de citation IA.
Ce n'est PAS un scraping en temps reel des IA. C'est un INDICE DE VISIBILITE estime.

# CE QUE TU DOIS FAIRE

1. **Analyse de la marque** : Identifie ce que les IA diraient probablement sur cette marque base sur :
   - Sa presence web connue
   - Son secteur d'activite
   - Sa notoriete estimee
   - La qualite de son contenu (si URL fournie)

2. **Simulation de mentions** : Genere des exemples realistes de comment les IA pourraient mentionner cette marque dans :
   - Des comparaisons de produits/services
   - Des recommandations a des utilisateurs
   - Des reponses a des questions sectorielles
   - Des listes de "meilleurs" ou "top"

3. **Analyse de sentiment** : Pour chaque mention simulee, evalue :
   - Le sentiment global (-100 a +100)
   - Le type de mention (directe, indirecte, comparaison, absente)
   - Les themes associes

4. **Detection de risques** : Identifie :
   - Les questions ou la marque est ABSENTE des reponses IA (risque majeur)
   - Les questions ou les concurrents sont cites mais PAS la marque
   - Les associations negatives potentielles

5. **Recommandations** : Genere des actions concretes pour :
   - Ameliorer la visibilite IA
   - Corriger les associations negatives
   - Combler les lacunes de contenu

# REGLES
- Reste REALISTE dans les simulations (pas de scores parfaits)
