// ================================================================
// SCAN REPUTATION
// ================================================================

export const scanReputation = async (input: ReputationScanInput, locale: 'fr' | 'en' | 'es' = 'fr'): Promise<ReputationReport> => {
  const apiKey = getApiKey();
  if (!apiKey) return fallbackReport(input);

  try {
    const ai = new GoogleGenAI({ apiKey });

    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        overallSentiment: { type: Type.NUMBER },
        visibilityScore: { type: Type.NUMBER },
        totalMentions: { type: Type.NUMBER },
        sentimentBreakdown: {
          type: Type.OBJECT,
          properties: {
            positive: { type: Type.NUMBER },
            neutral: { type: Type.NUMBER },
            negative: { type: Type.NUMBER }
          },
          required: ["positive", "neutral", "negative"]
        },
        topThemes: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              theme: { type: Type.STRING },
              count: { type: Type.NUMBER },
              sentiment: { type: Type.STRING }
            },
            required: ["theme", "count", "sentiment"]
          }
        },
        alerts: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              severity: { type: Type.STRING },
              message: { type: Type.STRING },
              action: { type: Type.STRING }
            },
            required: ["severity", "message", "action"]
          }
        },
        competitorComparison: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              mentions: { type: Type.NUMBER },
              sentiment: { type: Type.NUMBER }
            },
            required: ["name", "mentions", "sentiment"]
          }
        },
        recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
        mentions: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              aiEngine: { type: Type.STRING },
              prompt: { type: Type.STRING },
              mentionType: { type: Type.STRING },
              sentiment: { type: Type.STRING },
              sentimentScore: { type: Type.NUMBER },
              excerpt: { type: Type.STRING },
              context: { type: Type.STRING }
            },
            required: ["aiEngine", "prompt", "mentionType", "sentiment", "sentimentScore", "excerpt", "context"]
          }
        }
      },
      required: ["overallSentiment", "visibilityScore", "totalMentions", "sentimentBreakdown", "topThemes", "competitorComparison", "alerts", "recommendations", "mentions"]
    };

    const langInstruction = locale === 'en' ? 'Respond ENTIRELY in English.' : locale === 'es' ? 'Responde INTEGRAMENTE en espanol.' : 'Reponds INTEGRALEMENT en francais.';

    const userPrompt = `
      ${langInstruction}

      Analyse la reputation IA de cette marque :

      MARQUE : ${input.brandName}
      URL : ${input.brandUrl || 'Non fournie'}
      SECTEUR : ${input.industry}
      CONCURRENTS : ${(input.competitors || []).join(', ') || 'Non specifies'}
      MOTS-CLES SURVEILLES : ${(input.keywords || []).join(', ') || 'Non specifies'}

      Genere un rapport complet de reputation IA avec au minimum 6 mentions simulees.
      IMPORTANT : Tout le contenu du rapport (themes, messages, recommandations, excerpts) doit etre dans la langue specifiee ci-dessus.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
        systemInstruction: REPUTATION_SCAN_PROMPT,
        responseMimeType: 'application/json',
        responseSchema: schema,
        temperature: 0.5,
      }
    });

    let output = response.text;
    if (!output) throw new Error("Empty response");
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(output);

    return {
      brandName: input.brandName,
      overallSentiment: parsed.overallSentiment,
      visibilityScore: parsed.visibilityScore,
      totalMentions: parsed.totalMentions,
      sentimentBreakdown: parsed.sentimentBreakdown,
      topThemes: parsed.topThemes,
      competitorComparison: parsed.competitorComparison || (input.competitors || []).map(c => ({
        name: c, mentions: 0, sentiment: 0
      })),
      alerts: parsed.alerts,
      recommendations: parsed.recommendations,
      mentions: parsed.mentions.map((m: any, i: number) => ({
        ...m,
        id: String(i + 1),
        date: new Date().toISOString()
      })),
      generatedAt: new Date().toISOString()
    };
  } catch (error) {
    console.error("Reputation scan failed:", error); // TODO: Replace with proper error reporting (Sentry)
    return fallbackReport(input);
  }
};

