export const generateReputationResponse = async (alert: { message: string; action: string }, brandName: string, locale: 'fr' | 'en' | 'es' = 'fr'): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) {
    await new Promise(r => setTimeout(r, 1500));
    return `# Plan d'Action [SIMULATION]\n\n## Probleme\n${alert.message}\n\n## Actions Recommandees\n1. ${alert.action}\n2. Publier du contenu Answer-First\n3. Renforcer le Schema.org\n\n*Configurez votre cle API pour un plan d'action detaille.*`;
  }

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `${locale === 'en' ? 'Respond ENTIRELY in English.' : locale === 'es' ? 'Responde INTEGRAMENTE en espanol.' : 'Reponds INTEGRALEMENT en francais.'}\n\nMarque: ${brandName}\nProbleme detecte: ${alert.message}\nAction suggeree: ${alert.action}\n\nGenere un plan d'action detaille pour corriger cette situation.`,
      config: {
        systemInstruction: RESPONSE_GENERATOR_PROMPT,
        temperature: 0.4,
      }
    });
    return response.text || "Erreur de generation.";
  } catch (e) {
    console.error(e); // TODO: Replace with proper error reporting (Sentry)
    return "Erreur lors de la generation du plan d'action.";
  }
};
